# Product class hierarchy with interfaces

from types import IPriceable, IDiscountable, OrderStatus

class Product(IPriceable, IDiscountable):
    name: str
    base_price: float

    def __init__(self, name: str, price: float):
        self.name = name
        self.base_price = price

    def get_price(self) -> float:
        return self.base_price

    def apply_discount(self, percent: float) -> float:
        return self.base_price * (1.0 - percent / 100.0)

class DigitalProduct(Product):
    license_key: str

    def __init__(self, name: str, price: float, key: str):
        super().__init__(name, price)
        self.license_key = key

    def get_price(self) -> float:
        # Digital products have no tax
        return self.base_price * 0.95

class PhysicalProduct(Product):
    weight_kg: float
    shipping_cost: float

    def __init__(self, name: str, price: float, weight: float):
        super().__init__(name, price)
        self.weight_kg = weight
        self.shipping_cost = weight * 2.0

    def get_price(self) -> float:
        # Physical products include shipping
        return self.base_price + self.shipping_cost

class StatusTracker:
    current_status: OrderStatus

    def __init__(self):
        self.current_status = OrderStatus.PENDING

    def advance(self):
        if self.current_status == OrderStatus.PENDING:
            self.current_status = OrderStatus.CONFIRMED
        elif self.current_status == OrderStatus.CONFIRMED:
            self.current_status = OrderStatus.SHIPPED
        elif self.current_status == OrderStatus.SHIPPED:
            self.current_status = OrderStatus.DELIVERED

