# Order processing with cross-module imports

from types import IPriceable, ILoggable, OrderStatus
from products import Product, DigitalProduct, PhysicalProduct, StatusTracker

class OrderItem:
    product: IPriceable
    quantity: int

    def __init__(self, product: IPriceable, qty: int):
        self.product = product
        self.quantity = qty

    def subtotal(self) -> float:
        return self.product.get_price() * self.quantity

class Order(ILoggable):
    order_id: int
    items: list[OrderItem]
    tracker: StatusTracker

    def __init__(self, id: int):
        self.order_id = id
        self.items = []
        self.tracker = StatusTracker()

    def add_item(self, item: OrderItem):
        self.items.append(item)

    def total(self) -> float:
        total: float = 0.0
        for item in self.items:
            total = total + item.subtotal()
        return total

    def log_entry(self) -> str:
        return "Order #" + str(self.order_id)

    def get_status(self) -> OrderStatus:
        return self.tracker.current_status

    def advance_status(self):
        self.tracker.advance()

def calculate_savings(product: Product, discount: float) -> float:
    original: float = product.get_price()
    discounted: float = original * (1.0 - discount / 100.0)
    return original - discounted
